export const EmailEventWritableSchema = {
  type: "object",
  additionalProperties: false,
  required: ["type", "occurred_at", "recipient_id"],
  properties: {
    type: {
      type: "string",
      minLength: 1,
      description:
        "Event type. One of: `email.accepted`, `email.processed`, `email.deferred`, `email.delivered`, `email.bounced`, `email.out_of_band_bounce`, `email.complained`, `email.rejected`, `email.opened`, `email.clicked`, `email.unsubscribed`, `email.list_unsubscribed`.\n`email.processed` means Bird has processed the message and queued it for delivery.\n",
      example: "email.delivered",
    },
    occurred_at: {
      type: "string",
      format: "date-time",
      minLength: 1,
      description: "When this event occurred.",
    },
    recipient_id: {
      $ref: "#/components/schemas/RecipientID",
      description: "Recipient this event applies to.",
    },
    bounce_type: {
      type: ["string", "null"],
      enum: ["hard", "soft", "undetermined", "admin", "block", null],
      description:
        "Bounce classification. Present on `email.bounced`, `email.out_of_band_bounce`, and `email.deferred` events. `hard` is a permanent failure (invalid address or non-existent domain). `soft` is a transient failure (mailbox full, server temporarily unavailable). `block` indicates the receiving mail server blocked the sending IP for reputation reasons. `admin` indicates an administrative refusal (relaying denied, blocklisted domain). `undetermined` is used when the receiving server's response is ambiguous.\n",
    },
    bounce_class: {
      type: ["integer", "null"],
      minimum: 1,
      maximum: 255,
      description:
        "Numeric bounce classification for fine-grained deliverability triage. Lets you distinguish, for example, a DNS failure from a spam block when both would be `bounce_type: soft` or `bounce_type: block`. Present on `email.bounced`, `email.out_of_band_bounce`, and `email.deferred`.\n",
    },
    bounce_code: {
      type: ["string", "null"],
      description:
        "SMTP status code returned by the receiving mail server. Present on `email.bounced` and `email.deferred` events.\n",
      example: "5.1.1",
    },
    bounce_description: {
      type: ["string", "null"],
      description:
        "Human-readable bounce reason. Present on `email.bounced` and `email.deferred` events.",
    },
    rejection_reason: {
      type: ["string", "null"],
      enum: [
        "recipient_suppressed",
        "transmission_failed",
        "generation_failure",
        "policy_rejection",
        null,
      ],
      description:
        "Specific cause of rejection. Present on `email.rejected` events only. See `EmailRecipient.rejection_reason` for the meaning of each value.\n",
    },
    sending_ip: {
      type: ["string", "null"],
      description:
        "The IP address Bird used to send this message. Useful when investigating deliverability issues that correlate with specific IPs. Present on `email.delivered`, `email.bounced`, `email.out_of_band_bounce`, and `email.deferred` events.\n",
    },
    is_prefetched: {
      type: ["boolean", "null"],
      description:
        "True when the open was auto-fetched by an inbox privacy feature (Apple Mail Privacy Protection, Gmail image proxy) rather than a real user action. Useful for accurate open-rate calculation. Present on `email.opened` only.\n",
    },
    url: {
      type: ["string", "null"],
      description: "The clicked URL. Present on `email.clicked` events.",
    },
    country: {
      type: ["string", "null"],
      minLength: 2,
      maxLength: 2,
      description:
        "ISO 3166-1 alpha-2 country code derived from the client IP. Present on `email.opened` and `email.clicked` events when available.",
      example: "US",
    },
    ip_address: {
      type: ["string", "null"],
      description:
        "Client IP address (IPv4 or IPv6). Present on `email.opened` and `email.clicked` events when available.",
    },
    user_agent: {
      type: ["string", "null"],
      description:
        "Client user-agent string. Present on `email.opened` and `email.clicked` events when available.",
    },
  },
} as const;

